import React, { useState, useEffect } from "react";
import "./App.css";
import mondaySdk from "monday-sdk-js";
import "monday-ui-react-core/dist/main.css";
import ListInputMod from "./modules/ListInputMod.js";

const monday = mondaySdk();
const redirect_uri = "https://b8b8cbc2a52f.ngrok.app";
const client_id = "eb18d6836553020a3107559d979d31a8";
const client_secret = "ae0b0f705f2a9d99967c68fe1e61f308";

const App = () => {
  const [token, setToken] = useState(null);

  useEffect(() => {
    // Check if we have a code in the URL (returned from monday.com OAuth)
    const urlParams = new URLSearchParams(window.location.search);
    const code = urlParams.get('code');

    if (code) {
      // Exchange the code for a token
      fetch('https://27c4763d084d.ngrok.app/oauth/token', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({
          client_id,
          client_secret,
          code,
          redirect_uri
        })
      })
      .then(response => response.json())
      .then(data => {
        if (data.access_token) {
          setToken(data.access_token);
          monday.setToken(data.access_token);
        }
      })
      .catch(error => console.error('Error getting token:', error));
    } else {
      // If no code, redirect to monday.com OAuth
      window.location.href = 'https://auth.monday.com/oauth2/authorize?client_id=eb18d6836553020a3107559d979d31a8&redirect_uri=' + encodeURIComponent(redirect_uri);
    }
  }, []);



  return (
    <div className="App container">
      <div className="row mt-5">
        <div className="col-12 py-3 mt-5">
          <ListInputMod />
        </div>
      </div>
    </div>
  );
};

export default App;
